,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'AccidentToReview'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'    -- Update the project tab status',
'    UPDATE H_PROJECT_TAB',
'    SET STATUS_ID = (',
'        SELECT STATUS_ID ',
'        FROM H_PROJECT_TAB_STATUS ',
'        WHERE STATUS = ''In Review''',
'    )',
'    WHERE TAB_ID = (',
'        SELECT TAB_ID ',
'        FROM H_TAB ',
'        WHERE TAB_TYPE = ''ACCIDENTS''',
'    )',
'    AND PROJECT_ID = :P400_PROJECT_ID;',
'',
'    -- Update the accidents status',
'    UPDATE H_ACCIDENT_DATA ',
'    SET STATUS_ID = (',
'        SELECT STATUS_ID ',
'        FROM H_STATUS ',
'        WHERE STATUS_NAME = ''Under Review''',
'    )',
'    WHERE PROJECT_ID = :P400_PROJECT_ID;',
'END;',
'',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(81425461052186633924)
,p_internal_uid=>87844173492328991530
);
