,p_affected_elements=>'P411_POST_RISK'
,p_attribute_01=>'FUNCTION_BODY'
,p_attribute_06=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    lv_risk NUMBER;',
'BEGIN',
'',
'    IF :P411_POST_LIKELIHOOD IS NOT NULL ',
'       AND :P411_POST_SEVERITY IS NOT NULL THEN',
'',
'        lv_risk := :P411_POST_LIKELIHOOD + :P411_POST_SEVERITY;',
'',
'        IF lv_risk <= 3 THEN',
'            RETURN 1;',
'        ELSIF lv_risk = 4 THEN',
'            RETURN 2;',
'        ELSIF lv_risk <= 6 THEN',
'            RETURN 3;',
'        ELSIF lv_risk <= 8 THEN',
'            RETURN 4;',
'        ELSE',
'            RETURN 5;',
'        END IF;',
'    END IF;',
'',
'    RETURN NULL; ',
'END;',
''))
,p_attribute_07=>'P411_POST_SEVERITY,P411_POST_LIKELIHOOD'
,p_attribute_08=>'Y'
,p_attribute_09=>'N'
,p_wait_for_result=>'Y'
);
