,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'CauseToReview'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN ',
'UPDATE H_PROJECT_TAB',
'SET STATUS_ID = (SELECT STATUS_ID FROM H_PROJECT_TAB_STATUS WHERE STATUS = ''In Review'')',
'WHERE TAB_ID = (SELECT TAB_ID FROM H_TAB WHERE TAB_TYPE = ''CAUSES'')',
'AND PROJECT_ID = :P420_PROJECT_ID;',
'',
'    UPDATE H_CAUSE',
'    SET STATUS_ID = (',
'        SELECT STATUS_ID ',
'        FROM H_STATUS ',
'        WHERE STATUS_NAME = ''Under Review''',
'    )',
'    WHERE PROJECT_ID = :P420_PROJECT_ID;',
'',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(88595391271522498272)
