,p_process_name=>'ControlToReview'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN ',
'',
'UPDATE H_PROJECT_TAB',
'SET STATUS_ID = (SELECT STATUS_ID FROM H_PROJECT_TAB_STATUS WHERE STATUS = ''In Review'')',
'WHERE TAB_ID = (SELECT TAB_ID FROM H_TAB WHERE TAB_TYPE = ''CONTROLS'')',
'AND PROJECT_ID = :P430_PROJECT_ID;',
'',
'    UPDATE H_CONTROL',
'    SET STATUS_ID = (',
'        SELECT STATUS_ID ',
'        FROM H_STATUS ',
'        WHERE STATUS_NAME = ''Under Review''',
'    )',
'    WHERE PROJECT_ID = :P430_PROJECT_ID;',
'',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(88598721419168874727)
,p_internal_uid=>88599432185722577825
);
