wwv_flow_imp_page.create_page(
 p_id=>5000
,p_name=>'Hazard Identification'
,p_alias=>'HAZARD-IDENTIFICATION'
,p_step_title=>'Hazard Identification'
,p_autocomplete_on_off=>'OFF'
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'18'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(88625523270526421317)
,p_plug_name=>'Generated Query'
,p_region_name=>'generated_query_ir'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>40
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    a.ACCIDENT_ID,',
'    a.ACCIDENT_CODE,',
'    a.ACCIDENT_NAME || '' - '' || a.ACCIDENT_DESCRIPTION AS ACCIDENT_DETAIL,',
'    s.status_name as ACCIDENT_STATUS,',
'    ',
'    -- Distinct hazard details ordered by code',
'    LISTAGG(DISTINCT h.hazard_detail, '' | '')',
'    WITHIN GROUP (ORDER BY h.hazard_code) AS HAZARDS,',
'    ',
'    -- Distinct cause details ordered by code',
'    LISTAGG(DISTINCT c.cause_detail, '' | '') ',
'        WITHIN GROUP (ORDER BY c.cause_code) AS CAUSES,',
'',
'',
'    p.project_name AS PROJECT_NAME,',
'    p.project_description AS PROJECT_DESCRIPTION',
'',
'FROM H_ACCIDENT_DATA a',
'',
'-- Hazards (distinct per accident)',
'LEFT JOIN (',
'    SELECT DISTINCT',
'        ah.ACCIDENT_ID,',
'        h.HAZARD_CODE AS hazard_code,',
'        h.HAZARD_CODE || '':'' || h.HAZARD_NAME || '':Risk='' || h.INITIAL_RISK || '' ('' || s.STATUS_NAME || '')'' AS hazard_detail',
'    FROM H_LINK_ACCIDENT_HAZARD ah',
'    JOIN H_HAZARD h ON ah.HAZARD_ID = h.HAZARD_ID',
'    JOIN H_STATUS s ON h.STATUS_ID = s.STATUS_ID',
') h ON a.ACCIDENT_ID = h.ACCIDENT_ID',
'',
'-- Causes (distinct per accident)',
'LEFT JOIN (',
'    SELECT DISTINCT',
'        ac.ACCIDENT_ID,',
'        c.CAUSE_CODE AS cause_code,',
'        c.CAUSE_CODE || '':'' || c.CAUSE_NAME || '' ('' || s.STATUS_NAME || '')'' AS cause_detail',
'    FROM H_LINK_ACCIDENT_CAUSE ac',
'    JOIN H_CAUSE c ON ac.CAUSE_ID = c.CAUSE_ID',
'    JOIN H_STATUS s ON c.STATUS_ID = s.STATUS_ID',
') c ON a.ACCIDENT_ID = c.ACCIDENT_ID',
'',
'-- Accident status',
'JOIN H_STATUS s ON a.STATUS_ID = s.STATUS_ID',
'JOIN H_PROJECT P ON a.project_id = p.project_ID',
'',
'WHERE a.PROJECT_ID = :P5000_PROJECT_ID',
'GROUP BY a.ACCIDENT_ID, a.ACCIDENT_CODE, a.ACCIDENT_NAME, a.ACCIDENT_DESCRIPTION, s.status_name, p.project_name, P.project_description',
'ORDER BY a.ACCIDENT_ID;',
''))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P5000_PROJECT_ID'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'INCHES'
,p_prn_paper_size=>'LETTER'
,p_prn_width=>11
,p_prn_height=>8.5
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
,p_prn_page_header_font_size=>'12'
,p_prn_page_footer_font_color=>'#000000'
,p_prn_page_footer_font_family=>'Helvetica'
,p_prn_page_footer_font_weight=>'normal'
,p_prn_page_footer_font_size=>'12'
,p_prn_header_bg_color=>'#EEEEEE'
,p_prn_header_font_color=>'#000000'
,p_prn_header_font_family=>'Helvetica'
,p_prn_header_font_weight=>'bold'
,p_prn_header_font_size=>'10'
,p_prn_body_bg_color=>'#FFFFFF'
,p_prn_body_font_color=>'#000000'
,p_prn_body_font_family=>'Helvetica'
,p_prn_body_font_weight=>'normal'
,p_prn_body_font_size=>'10'
,p_prn_border_width=>.5
