,p_plug_display_sequence=>10
,p_plug_display_point=>'REGION_POSITION_01'
,p_menu_id=>wwv_flow_imp.id(72132883516406176952)
,p_plug_source_type=>'NATIVE_BREADCRUMB'
,p_menu_template_id=>4072363345357175094
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(89013160118640280781)
,p_plug_name=>'Control Identification'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>30
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    h.HAZARD_ID,',
'    h.HAZARD_CODE,',
'    h.HAZARD_NAME || '' - '' || h.HAZARD_DESCRIPTION AS HAZARD_DETAIL,',
'    h.INITIAL_RISK,',
'    h.POST_RISK,',
'    hs.STATUS_NAME AS HAZARD_STATUS,',
'',
'    -- Accidents linked to hazard',
'    LISTAGG(DISTINCT a.ACCIDENT_CODE || '':'' || a.ACCIDENT_NAME || '' ('' || ast.STATUS_NAME || '')'', '' | '') ',
'        WITHIN GROUP (ORDER BY a.ACCIDENT_CODE) AS ACCIDENTS,',
'',
'    -- Causes linked to hazard via accidents',
'    LISTAGG(DISTINCT c.CAUSE_CODE || '':'' || c.CAUSE_NAME || '' ('' || cs.STATUS_NAME || '')'', '' | '')',
'        WITHIN GROUP (ORDER BY c.CAUSE_CODE) AS CAUSES,',
'',
'    -- Controls linked to hazard',
'    LISTAGG(DISTINCT co.CONTROL_CODE || '':'' || co.CONTROL_NAME, '' | '')',
'        WITHIN GROUP (ORDER BY co.CONTROL_CODE) AS CONTROLS,',
'',
'    -- References linked to controls',
'    LISTAGG(DISTINCT r.REFERENCE_CODE || '':'' || r.REFERENCE_TITLE, '' | '')',
'        WITHIN GROUP (ORDER BY r.REFERENCE_CODE) AS REFERENCES',
'',
'FROM H_HAZARD h',
'',
'-- Hazard status',
'JOIN H_STATUS hs ON h.STATUS_ID = hs.STATUS_ID',
'',
'-- Link to accidents',
'LEFT JOIN H_LINK_ACCIDENT_HAZARD lah ON h.HAZARD_ID = lah.HAZARD_ID',
'LEFT JOIN H_ACCIDENT_DATA a ON lah.ACCIDENT_ID = a.ACCIDENT_ID',
'LEFT JOIN H_STATUS ast ON a.STATUS_ID = ast.STATUS_ID',
'',
'-- Link to causes via accidents',
'LEFT JOIN H_LINK_ACCIDENT_CAUSE lac ON a.ACCIDENT_ID = lac.ACCIDENT_ID',
'LEFT JOIN H_CAUSE c ON lac.CAUSE_ID = c.CAUSE_ID',
'LEFT JOIN H_STATUS cs ON c.STATUS_ID = cs.STATUS_ID',
'',
'-- Link to controls via hazard',
'LEFT JOIN H_LINK_HAZARD_CONTROL lhc ON h.HAZARD_ID = lhc.HAZARD_ID',
'LEFT JOIN H_CONTROL co ON lhc.CONTROL_ID = co.CONTROL_ID',
'',
'-- Link to references via controls',
'LEFT JOIN H_LINK_CONTROL_REFERENCE lcr ON co.CONTROL_ID = lcr.CONTROL_ID',
'LEFT JOIN H_REFERENCE r ON lcr.REFERENCE_ID = r.REFERENCE_ID',
'',
'WHERE h.PROJECT_ID = :P5001_PROJECT_ID',
'',
'GROUP BY h.HAZARD_ID, h.HAZARD_CODE, h.HAZARD_NAME, h.HAZARD_DESCRIPTION, h.INITIAL_RISK, h.POST_RISK, hs.STATUS_NAME',
'',
'ORDER BY h.HAZARD_CODE;',
''))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P5001_PROJECT_ID'
,p_prn_page_header=>'Control Identification'
);
