,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>60
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select HAZARD_ID, HAZARD_CODE, HAZARD_NAME,',
'(CASE ',
'     WHEN EXISTS (',
'       SELECT 1 ',
'       FROM H_LINK_ACCIDENT_HAZARD AH ',
'       WHERE AH.HAZARD_ID = H.HAZARD_ID ',
'         AND AH.ACCIDENT_ID = :P6000_ACCIDENT_ID',
'     ) THEN ''Y'' ',
'     ELSE ''N'' ',
'   END) AS LINK_ACCIDENT_HAZARD',
'  from H_HAZARD H',
'WHERE PROJECT_ID = (SELECT PROJECT_ID FROM H_ACCIDENT_DATA WHERE ACCIDENT_ID = :P6000_ACCIDENT_ID)',
'AND LOGICALLY_DELETED = ''N''',
