'WHERE T.TAB_TYPE = ''AccidentHazard''',
'AND PT.STATUS_ID = (SELECT STATUS_ID FROM H_PROJECT_TAB_STATUS WHERE STATUS = ''In Progress'')',
'AND PT.PROJECT_ID = :P0_PROJECT_ID'))
