 p_id=>wwv_flow_imp.id(109335543087911793313)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_region_id=>wwv_flow_imp.id(98691966142859641903)
,p_process_type=>'NATIVE_IG_DML'
,p_process_name=>'New'
,p_attribute_01=>'PLSQL_CODE'
,p_attribute_04=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_accident_id NUMBER := :P6000_ACCIDENT_ID;',
'    v_hazard_id   NUMBER := :HAZARD_ID; ',
'    v_link        VARCHAR2(1) := :LINK_ACCIDENT_HAZARD;',
'BEGIN',
'    IF v_link = ''Y'' THEN',
'        INSERT INTO H_LINK_ACCIDENT_HAZARD (',
'            ACCIDENT_ID, HAZARD_ID, CREATED_BY, CREATED_DATE, PROJECT_ID',
'        )',
'        SELECT v_accident_id, v_hazard_id, :APP_USER, SYSDATE,',
'               (SELECT PROJECT_ID FROM H_ACCIDENT_DATA WHERE ACCIDENT_ID = v_accident_id)',
'        FROM DUAL',
'        WHERE NOT EXISTS (',
'            SELECT 1 ',
'            FROM H_LINK_ACCIDENT_HAZARD',
'            WHERE ACCIDENT_ID = v_accident_id',
'              AND HAZARD_ID   = v_hazard_id',
'        );',
'    ELSIF v_link = ''N'' THEN',
'        DELETE FROM H_LINK_ACCIDENT_HAZARD',
'        WHERE ACCIDENT_ID = v_accident_id',
'          AND HAZARD_ID   = v_hazard_id;',
'    END IF;',
'END;',
''))
,p_attribute_05=>'Y'
,p_attribute_06=>'Y'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>109335543087911793313
);
end;
